# RUN: llvm-mca -mtriple=x86_64-unknown-unknown -mcpu=znver1 -instruction-tables < %s | FileCheck %s

# r,r,i
shld $4, %eax, %ebx
shld $4, %rax, %rbx

shrd $4, %eax, %ebx
shrd $4, %rax, %rbx

# r,r,cl
shld %cl, %eax, %ebx
shld %cl, %rax, %rbx

shrd %cl, %eax, %ebx
shrd %cl, %rax, %rbx

# m,r,i
shld $4, %eax, (%rbx)
shld $4, %rax, (%rbx)

shrd $4, %eax, (%rbx)
shrd $4, %rax, (%rbx)

# m,r,cl
shld %cl, %eax, (%rbx)
shld %cl, %rax, (%rbx)

shrd %cl, %eax, (%rbx)
shrd %cl, %rax, (%rbx)

